&lt;li style=&quot;font-weight: 400;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;Resourceful, and motivated to resolve issues whenever they arise&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-weight: 400;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;Customer service attitude&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-weight: 400;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;Microsoft Excel, Google Spreadsheets, and CLIO (Preferred)&lt;/span&gt;&lt;/li&gt;
&lt;li style=&quot;font-weight: 400;&quot;&gt;&lt;span style=&quot;font-weight: 400;&quot;&gt;Schedule: Full-time (40 hours/week)&amp;nbsp;&lt;br&gt;&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
